const emailResp = $.steps.fetchEmails.response || {};
const emailData = emailResp.data || emailResp;
const emails = emailData.messages || emailData.items || [];

const calResp = $.steps.fetchCalendarEvents.response || {};
const calData = calResp.data || calResp;
const events = calData.items || calData.events || [];

let emailSummary = 'UNREAD EMAILS (' + emails.length + '):\n';
emails.slice(0, 10).forEach((e, i) => {
  emailSummary += (i + 1) + '. ID: ' + (e.id || 'N/A') + ', Snippet: ' + (e.snippet || 'N/A').slice(0, 100) + '\n';
});

let calSummary = 'CALENDAR EVENTS (' + events.length + '):\n';
events.slice(0, 10).forEach((ev, i) => {
  const start = ev.start ? (ev.start.dateTime || ev.start.date || '') : '';
  const end = ev.end ? (ev.end.dateTime || ev.end.date || '') : '';
  calSummary += (i + 1) + '. ' + (ev.summary || 'No title') + ' | Start: ' + start + ' | End: ' + end + '\n';
});

const now = new Date();
const dateStr = now.toLocaleDateString('en-US', { weekday: 'long', year: 'numeric', month: 'long', day: 'numeric' });

return { emailSummary, calSummary, emailCount: emails.length, eventCount: events.length, dateStr };

const data = $.steps.compileBriefData.output;
const userName = $.input.userName || 'there';

let prompt = 'You are a personal assistant creating a daily briefing. Be concise, helpful, and prioritize what matters most.\n\n';
prompt += 'DATE: ' + data.dateStr + '\n';
prompt += 'USER: ' + userName + '\n\n';
prompt += data.emailSummary + '\n';
prompt += data.calSummary + '\n';
prompt += 'INSTRUCTIONS:\n';
prompt += '- Create a personalized morning brief\n';
prompt += '- Prioritize urgent emails and upcoming meetings\n';
prompt += '- Suggest time blocks for the day\n';
prompt += '- Flag any potential conflicts or urgent items\n';
prompt += '- Keep the tone warm but professional\n\n';
prompt += 'Return ONLY valid JSON:\n';
prompt += '{\n';
prompt += '  "greeting": "Good morning greeting",\n';
prompt += '  "urgentItems": ["urgent thing 1"],\n';
prompt += '  "emailHighlights": [{ "summary": "email desc", "priority": "high/medium/low" }],\n';
prompt += '  "schedule": [{ "time": "9:00 AM", "event": "meeting name", "notes": "preparation needed" }],\n';
prompt += '  "suggestedTimeBlocks": [{ "time": "10:00-11:00", "activity": "focus work" }],\n';
prompt += '  "dayOverview": "1-2 sentence day summary",\n';
prompt += '  "tip": "A helpful productivity tip"\n';
prompt += '}';

return { prompt };

let raw = $.steps.aiBrief.output || '';
raw = raw.replace(/^```json\s*/i, '').replace(/^```\s*/i, '').replace(/\s*```$/i, '').trim();
try { return JSON.parse(raw); } catch(e) { return { greeting: 'Good morning!', urgentItems: [], emailHighlights: [], schedule: [], suggestedTimeBlocks: [], dayOverview: raw, tip: '' }; }

const ai = $.steps.parseAI.output;
const data = $.steps.compileBriefData.output;

const blocks = [];
blocks.push({ type: 'header', text: { type: 'plain_text', text: 'Daily Brief — ' + data.dateStr, emoji: true } });
blocks.push({ type: 'section', text: { type: 'mrkdwn', text: ai.greeting || 'Good morning!' } });
blocks.push({ type: 'section', fields: [
  { type: 'mrkdwn', text: '*:email: Unread Emails:*\n' + data.emailCount },
  { type: 'mrkdwn', text: '*:calendar: Events Today:*\n' + data.eventCount }
] });

if (ai.urgentItems && ai.urgentItems.length > 0) {
  blocks.push({ type: 'divider' });
  let urgentText = '*:rotating_light: Urgent:*\n';
  ai.urgentItems.forEach(item => { urgentText += '- ' + item + '\n'; });
  blocks.push({ type: 'section', text: { type: 'mrkdwn', text: urgentText.slice(0, 1000) } });
}

if (ai.schedule && ai.schedule.length > 0) {
  blocks.push({ type: 'divider' });
  let schedText = '*:clock9: Schedule:*\n';
  ai.schedule.slice(0, 6).forEach(s => {
    schedText += '*' + s.time + '* - ' + s.event;
    if (s.notes) schedText += ' _(' + s.notes + ')_';
    schedText += '\n';
  });
  blocks.push({ type: 'section', text: { type: 'mrkdwn', text: schedText.slice(0, 1500) } });
}

if (ai.emailHighlights && ai.emailHighlights.length > 0) {
  blocks.push({ type: 'divider' });
  let emailText = '*:envelope: Email Highlights:*\n';
  ai.emailHighlights.slice(0, 5).forEach(e => {
    const icon = e.priority === 'high' ? ':red_circle:' : ':large_blue_circle:';
    emailText += icon + ' ' + e.summary + '\n';
  });
  blocks.push({ type: 'section', text: { type: 'mrkdwn', text: emailText.slice(0, 1500) } });
}

if (ai.suggestedTimeBlocks && ai.suggestedTimeBlocks.length > 0) {
  blocks.push({ type: 'divider' });
  let tbText = '*:hourglass: Suggested Focus Blocks:*\n';
  ai.suggestedTimeBlocks.slice(0, 4).forEach(tb => { tbText += tb.time + ' — ' + tb.activity + '\n'; });
  blocks.push({ type: 'section', text: { type: 'mrkdwn', text: tbText.slice(0, 1000) } });
}

if (ai.dayOverview) {
  blocks.push({ type: 'section', text: { type: 'mrkdwn', text: '*Overview:* ' + ai.dayOverview.slice(0, 500) } });
}

if (ai.tip) {
  blocks.push({ type: 'context', elements: [{ type: 'mrkdwn', text: ':bulb: ' + ai.tip }] });
}

blocks.push({ type: 'divider' });
blocks.push({ type: 'context', elements: [{ type: 'mrkdwn', text: 'Powered by Gmail + Calendar + Claude AI + One CLI' }] });

const fallback = 'Daily Brief: ' + data.emailCount + ' emails, ' + data.eventCount + ' events - ' + (ai.dayOverview || '').slice(0, 100);
return { blocks, fallback };
